  1→import type { RecordId } from "surrealdb";
  2→
  3→// ---------------------------------------------------------------------------
  4→// Rule Predicates & Conditions
  5→// ---------------------------------------------------------------------------
  6→
  7→export type RulePredicate = {
  8→  field: string;
  9→  operator:
 10→    | "eq"
 11→    | "neq"
 12→    | "lt"
 13→    | "lte"
 14→    | "gt"
 15→    | "gte"
 16→    | "in"
 17→    | "not_in"
 18→    | "exists";
 19→  value: string | number | boolean | string[];
 20→};
 21→
 22→export type RuleCondition = RulePredicate | RulePredicate[];
 23→
 24→// ---------------------------------------------------------------------------
 25→// Policy Domain Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type PolicyRule = {
 29→  id: string;
 30→  condition: RuleCondition;
 31→  effect: "allow" | "deny";
 32→  priority: number;
 33→};
 34→
 35→export type PolicySelector = {
 36→  workspace?: string;
 37→  agent_role?: string;
 38→  resource?: string;
 39→};
 40→
 41→export type PolicyStatus =
 42→  | "draft"
 43→  | "testing"
 44→  | "active"
 45→  | "deprecated"
 46→  | "superseded";
 47→
 48→export type PolicyRecord = {
 49→  id: RecordId<"policy">;
 50→  title: string;
 51→  description?: string;
 52→  version: number;
 53→  status: PolicyStatus;
 54→  selector: PolicySelector;
 55→  rules: PolicyRule[];
 56→  human_veto_required: boolean;
 57→  max_ttl?: string;
 58→  created_by: RecordId<"identity">;
 59→  workspace: RecordId<"workspace">;
 60→  supersedes?: RecordId<"policy">;
 61→  created_at: Date;
 62→  updated_at?: Date;
 63→};
 64→
 65→// ---------------------------------------------------------------------------
 66→// Policy Trace (recorded on intent.evaluation)
 67→// ---------------------------------------------------------------------------
 68→
 69→export type PolicyTraceEntry = {
 70→  policy_id: string;
 71→  policy_version: number;
 72→  rule_id: string;
 73→  effect: "allow" | "deny";
 74→  matched: boolean;
 75→  priority: number;
 76→};
 77→
 78→// ---------------------------------------------------------------------------
 79→// Policy Gate Result (output of policy evaluation pipeline)
 80→// ---------------------------------------------------------------------------
 81→
 82→export type PolicyGateWarning = {
 83→  rule_id: string;
 84→  field: string;
 85→  policy_id: string;
 86→};
 87→
 88→export type PolicyGateResult =
 89→  | {
 90→      passed: true;
 91→      policy_trace: PolicyTraceEntry[];
 92→      human_veto_required: boolean;
 93→      warnings: PolicyGateWarning[];
 94→    }
 95→  | {
 96→      passed: false;
 97→      reason: string;
 98→      policy_trace: PolicyTraceEntry[];
 99→      deny_rule_id: string;
100→      warnings: PolicyGateWarning[];
101→    };
102→
103→// ---------------------------------------------------------------------------
104→// Intent Evaluation Context (input to policy gate)
105→// ---------------------------------------------------------------------------
106→
107→export type IntentEvaluationContext = {
108→  goal: string;
109→  reasoning: string;
110→  priority: number;
111→  action_spec: {
112→    provider: string;
113→    action: string;
114→    params?: Record<string, unknown>;
115→  };
116→  budget_limit?: { amount: number; currency: string };
117→  authorization_details?: Array<{
118→    type: string;
119→    action: string;
120→    resource: string;
121→    constraints?: Record<string, unknown>;
122→  }>;
123→  requester_type: string;
124→  requester_role?: string;
125→};
126→

  1→import type { RecordId, Surreal } from "surrealdb";
  2→import type {
  3→  PolicyRecord,
  4→  PolicyRule,
  5→  PolicyGateResult,
  6→  PolicyTraceEntry,
  7→  PolicyGateWarning,
  8→  IntentEvaluationContext,
  9→} from "./types";
 10→import { evaluateCondition } from "./predicate-evaluator";
 11→import { loadActivePolicies } from "./policy-queries";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Pipeline Types
 15→// ---------------------------------------------------------------------------
 16→
 17→type AnnotatedRule = {
 18→  policyId: string;
 19→  policyVersion: number;
 20→  humanVetoRequired: boolean;
 21→  rule: PolicyRule;
 22→};
 23→
 24→type EvaluatedRule = AnnotatedRule & {
 25→  matched: boolean;
 26→  warnings: PolicyGateWarning[];
 27→};
 28→
 29→type EvaluationResult = {
 30→  evaluatedRules: EvaluatedRule[];
 31→  denyMatched: boolean;
 32→  warnings: PolicyGateWarning[];
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Pure Pipeline Functions
 37→// ---------------------------------------------------------------------------
 38→
 39→export const deduplicatePolicies = (
 40→  policies: PolicyRecord[],
 41→): PolicyRecord[] => {
 42→  const seen = new Set<string>();
 43→  const result: PolicyRecord[] = [];
 44→
 45→  for (const policy of policies) {
 46→    const id = policy.id.id as string;
 47→    if (!seen.has(id)) {
 48→      seen.add(id);
 49→      result.push(policy);
 50→    }
 51→  }
 52→
 53→  return result;
 54→};
 55→
 56→export const collectAndSortRules = (
 57→  policies: PolicyRecord[],
 58→): AnnotatedRule[] => {
 59→  const annotated = policies.flatMap((policy) =>
 60→    policy.rules.map((rule) => ({
 61→      policyId: policy.id.id as string,
 62→      policyVersion: policy.version,
 63→      humanVetoRequired: policy.human_veto_required,
 64→      rule,
 65→    })),
 66→  );
 67→
 68→  return annotated.sort((a, b) => b.rule.priority - a.rule.priority);
 69→};
 70→
 71→export const evaluateRulesAgainstContext = (
 72→  rules: AnnotatedRule[],
 73→  context: IntentEvaluationContext,
 74→): EvaluationResult => {
 75→  const contextRecord = context as unknown as Record<string, unknown>;
 76→  const evaluatedRules: EvaluatedRule[] = [];
 77→  const allWarnings: PolicyGateWarning[] = [];
 78→
 79→  for (const annotated of rules) {
 80→    const { matched, warnings } = evaluateCondition(
 81→      contextRecord,
 82→      annotated.rule.condition,
 83→      annotated.rule.id,
 84→      annotated.policyId,
 85→    );
 86→
 87→    allWarnings.push(...warnings);
 88→    evaluatedRules.push({ ...annotated, matched, warnings });
 89→
 90→    if (matched && annotated.rule.effect === "deny") {
 91→      return {
 92→        evaluatedRules,
 93→        denyMatched: true,
 94→        warnings: allWarnings,
 95→      };
 96→    }
 97→  }
 98→
 99→  return {
100→    evaluatedRules,
101→    denyMatched: false,
102→    warnings: allWarnings,
103→  };
104→};
105→
106→export const buildGateResult = (
107→  evaluatedRules: EvaluatedRule[],
108→  denyMatched: boolean,
109→  warnings: PolicyGateWarning[],
110→): PolicyGateResult => {
111→  const policyTrace: PolicyTraceEntry[] = evaluatedRules.map((entry) => ({
112→    policy_id: entry.policyId,
113→    policy_version: entry.policyVersion,
114→    rule_id: entry.rule.id,
115→    effect: entry.rule.effect,
116→    matched: entry.matched,
117→    priority: entry.rule.priority,
118→  }));
119→
120→  if (denyMatched) {
121→    const denyRule = evaluatedRules.find(
122→      (entry) => entry.matched && entry.rule.effect === "deny",
123→    );
124→    return {
125→      passed: false,
126→      reason: `Policy deny rule '${denyRule!.rule.id}' matched`,
127→      policy_trace: policyTrace,
128→      deny_rule_id: denyRule!.rule.id,
129→      warnings,
130→    };
131→  }
132→
133→  const humanVetoRequired = evaluatedRules.some(
134→    (entry) => entry.humanVetoRequired,
135→  );
136→
137→  return {
138→    passed: true,
139→    policy_trace: policyTrace,
140→    human_veto_required: humanVetoRequired,
141→    warnings,
142→  };
143→};
144→
145→// ---------------------------------------------------------------------------
146→// Composition Root (single effect boundary)
147→// ---------------------------------------------------------------------------
148→
149→export const evaluatePolicyGate = async (
150→  surreal: Surreal,
151→  identityId: RecordId<"identity">,
152→  workspaceId: RecordId<"workspace">,
153→  intentContext: IntentEvaluationContext,
154→): Promise<PolicyGateResult> => {
155→  // Effect boundary: single DB read
156→  const rawPolicies = await loadActivePolicies(surreal, identityId, workspaceId);
157→
158→  // Pure pipeline
159→  const deduplicated = deduplicatePolicies(rawPolicies);
160→  const sortedRules = collectAndSortRules(deduplicated);
161→  const { evaluatedRules, denyMatched, warnings } = evaluateRulesAgainstContext(
162→    sortedRules,
163→    intentContext,
164→  );
165→
166→  return buildGateResult(evaluatedRules, denyMatched, warnings);
167→};
168→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { PolicyRecord, PolicyRule, PolicySelector } from "./types";
  3→
  4→// --- Parameter Types ---
  5→
  6→type CreatePolicyParams = {
  7→  title: string;
  8→  description?: string;
  9→  selector?: PolicySelector;
 10→  rules: PolicyRule[];
 11→  human_veto_required?: boolean;
 12→  max_ttl?: string;
 13→  createdBy: RecordId<"identity">;
 14→  workspace: RecordId<"workspace">;
 15→};
 16→
 17→// --- Query Functions ---
 18→
 19→export async function loadActivePolicies(
 20→  surreal: Surreal,
 21→  identityId: RecordId<"identity">,
 22→  workspaceId: RecordId<"workspace">,
 23→): Promise<PolicyRecord[]> {
 24→  const identityResult = await surreal.query<
 25→    [Array<{ policies: PolicyRecord[] }>]
 26→  >(
 27→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 28→    { identity: identityId },
 29→  );
 30→
 31→  const workspaceResult = await surreal.query<
 32→    [Array<{ policies: PolicyRecord[] }>]
 33→  >(
 34→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 35→    { workspace: workspaceId },
 36→  );
 37→
 38→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 39→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 40→
 41→  // Deduplicate by policy ID and filter active only
 42→  const seen = new Set<string>();
 43→  const result: PolicyRecord[] = [];
 44→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 45→    const id = policy.id.id as string;
 46→    if (!seen.has(id) && policy.status === "active") {
 47→      seen.add(id);
 48→      result.push(policy);
 49→    }
 50→  }
 51→  return result;
 52→}
 53→
 54→export async function createPolicy(
 55→  surreal: Surreal,
 56→  params: CreatePolicyParams,
 57→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
 58→  const policyId = `policy-${crypto.randomUUID()}`;
 59→  const policyRecord = new RecordId("policy", policyId);
 60→
 61→  const content: Record<string, unknown> = {
 62→    title: params.title,
 63→    version: 1,
 64→    status: "draft",
 65→    selector: params.selector ?? {},
 66→    rules: params.rules,
 67→    human_veto_required: params.human_veto_required ?? false,
 68→    created_by: params.createdBy,
 69→    workspace: params.workspace,
 70→    created_at: new Date(),
 71→  };
 72→
 73→  if (params.description) content.description = params.description;
 74→  if (params.max_ttl) content.max_ttl = params.max_ttl;
 75→
 76→  await surreal.query("CREATE $policy CONTENT $content;", {
 77→    policy: policyRecord,
 78→    content,
 79→  });
 80→
 81→  return { policyId, policyRecord };
 82→}
 83→
 84→export async function activatePolicy(
 85→  surreal: Surreal,
 86→  policyId: string,
 87→  creatorId: RecordId<"identity">,
 88→  workspaceId: RecordId<"workspace">,
 89→): Promise<void> {
 90→  const policyRecord = new RecordId("policy", policyId);
 91→
 92→  await surreal.query(
 93→    `
 94→    BEGIN TRANSACTION;
 95→      UPDATE $policy SET status = 'active', updated_at = time::now();
 96→      RELATE $creator->governing->$policy SET created_at = time::now();
 97→      RELATE $policy->protects->$workspace SET created_at = time::now();
 98→    COMMIT TRANSACTION;
 99→  `,
100→    {
101→      policy: policyRecord,
102→      creator: creatorId,
103→      workspace: workspaceId,
104→    },
105→  );
106→}
107→
108→export async function deprecatePolicy(
109→  surreal: Surreal,
110→  policyId: string,
111→): Promise<void> {
112→  const policyRecord = new RecordId("policy", policyId);
113→
114→  await surreal.query(
115→    `
116→    BEGIN TRANSACTION;
117→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
118→      DELETE governing WHERE out = $policy;
119→      DELETE protects WHERE in = $policy;
120→    COMMIT TRANSACTION;
121→  `,
122→    { policy: policyRecord },
123→  );
124→}
125→
126→export async function createPolicyAuditEvent(
127→  surreal: Surreal,
128→  eventType: string,
129→  actor: RecordId<"identity">,
130→  workspace: RecordId<"workspace">,
131→  policyId: string,
132→  version: number,
133→): Promise<void> {
134→  const auditId = `audit-${crypto.randomUUID()}`;
135→  const auditRecord = new RecordId("audit_event", auditId);
136→
137→  await surreal.query("CREATE $audit CONTENT $content;", {
138→    audit: auditRecord,
139→    content: {
140→      event_type: eventType,
141→      actor,
142→      workspace,
143→      payload: {
144→        policy_id: policyId,
145→        policy_version: version,
146→      },
147→      severity: "info",
148→      created_at: new Date(),
149→    },
150→  });
151→}
