 3→-- Policy table: governance rules for intent authorization
 4→DEFINE TABLE OVERWRITE policy SCHEMAFULL;
 5→DEFINE FIELD title ON policy TYPE string;
 6→DEFINE FIELD description ON policy TYPE option<string>;
 7→DEFINE FIELD version ON policy TYPE int ASSERT $value > 0;
 8→DEFINE FIELD status ON policy TYPE string
 9→  ASSERT $value IN ['active', 'draft', 'deprecated', 'testing', 'superseded'];
10→DEFINE FIELD selector ON policy TYPE object;
11→DEFINE FIELD selector.workspace ON policy TYPE option<string>;
12→DEFINE FIELD selector.agent_role ON policy TYPE option<string>;
13→DEFINE FIELD selector.resource ON policy TYPE option<string>;
14→DEFINE FIELD rules ON policy TYPE array<object>;
15→DEFINE FIELD rules[*].id ON policy TYPE string;
16→DEFINE FIELD rules[*].condition ON policy TYPE object | array FLEXIBLE;
17→DEFINE FIELD rules[*].condition[*].field ON policy TYPE option<string>;
18→DEFINE FIELD rules[*].condition[*].operator ON policy TYPE option<string>;
19→DEFINE FIELD rules[*].effect ON policy TYPE string ASSERT $value IN ['allow', 'deny'];
20→DEFINE FIELD rules[*].priority ON policy TYPE int;
21→DEFINE FIELD human_veto_required ON policy TYPE bool DEFAULT false;
22→DEFINE FIELD max_ttl ON policy TYPE option<string>;
23→DEFINE FIELD created_by ON policy TYPE record<identity>;
24→DEFINE FIELD workspace ON policy TYPE record<workspace>;
25→DEFINE FIELD supersedes ON policy TYPE option<record<policy>>;
26→DEFINE FIELD created_at ON policy TYPE datetime;
27→DEFINE FIELD updated_at ON policy TYPE option<datetime>;
28→DEFINE INDEX policy_status ON policy FIELDS status;
29→DEFINE INDEX policy_workspace ON policy FIELDS workspace;
30→DEFINE INDEX policy_workspace_status ON policy FIELDS workspace, status;
31→
32→-- Graph relation: identity -governing-> policy
33→DEFINE TABLE OVERWRITE governing TYPE RELATION IN identity OUT policy SCHEMAFULL;
34→DEFINE FIELD created_at ON governing TYPE datetime;
35→DEFINE INDEX governing_out ON governing FIELDS out;
36→
37→-- Graph relation: policy -protects-> workspace
38→DEFINE TABLE OVERWRITE protects TYPE RELATION IN policy OUT workspace SCHEMAFULL;
39→DEFINE FIELD created_at ON protects TYPE datetime;
40→DEFINE INDEX protects_in ON protects FIELDS in;
41→
42→-- Extend intent.evaluation with policy_trace fields
43→DEFINE FIELD OVERWRITE evaluation.policy_trace ON intent TYPE option<array<object>>;
44→DEFINE FIELD evaluation.policy_trace[*].policy_id ON intent TYPE string;
45→DEFINE FIELD evaluation.policy_trace[*].policy_version ON intent TYPE int;
46→DEFINE FIELD evaluation.policy_trace[*].rule_id ON intent TYPE string;
47→DEFINE FIELD evaluation.policy_trace[*].effect ON intent TYPE string ASSERT $value IN ['allow', 'deny'];
48→DEFINE FIELD evaluation.policy_trace[*].matched ON intent TYPE bool;
49→DEFINE FIELD evaluation.policy_trace[*].priority ON intent TYPE int;
