 14→function resolveRecordId<T extends string>(
 15→  table: T,
 16→  ref: unknown,
 17→): RecordId<T> {
 18→  const rawId = typeof ref === "object" && ref !== null
 19→    ? ((ref as { id: unknown }).id as string)
