 33→function routingToTransition(
 34→  routing: RoutingDecision,
 35→  intentId: string,
 36→  evaluationRecord: Record<string, unknown>,
 37→): TransitionPlan {
 38→  switch (routing.route) {
 39→    case "auto_approve":
 40→      return {
 41→        targetStatus: "authorized",
 42→        updateFields: { evaluation: evaluationRecord },
 43→        logEvent: "intent.authorized",
