=== POLICY TEST KIT HELPERS ===
import { RecordId, type Surreal } from "surrealdb";

// Re-export everything from intent-test-kit (which re-exports orchestrator-test-kit)
export {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  createTestProject,
  getTestUserBearerToken,
  fetchJson,
  fetchRaw,
  createDraftIntent,
  submitIntent,
  getIntentStatus,
  getIntentRecord,
  getIntentEvaluation,
  waitForIntentStatus,
  simulateEvaluation,
  createTestIdentity,
  listPendingIntents,
  wireIntentEvaluationEvent,
  type OrchestratorTestRuntime,
  type TestUser,
  type TestUserWithToken,
  type TestWorkspace,
  type TestTask,
  type TestProject,
  type IntentStatus,
  type IntentRecord,
  type EvaluationResult,
  type ActionSpec,
  type BudgetLimit,
  type CreateIntentOptions,
} from "../intent-node/intent-test-kit";

// ---------------------------------------------------------------------------
// Policy-Specific Types
// ---------------------------------------------------------------------------

export type RulePredicate = {
  field: string;
  operator: "eq" | "neq" | "lt" | "lte" | "gt" | "gte" | "in" | "not_in" | "exists";
  value: string | number | boolean | string[];
};

export type RuleCondition = RulePredicate | RulePredicate[];

export type PolicyRule = {
  id: string;
  condition: RuleCondition;
  effect: "allow" | "deny";
  priority: number;
};

export type PolicySelector = {
  workspace?: string;
  agent_role?: string;
  resource?: string;
};

export type PolicyStatus = "draft" | "testing" | "active" | "deprecated" | "superseded";

export type PolicyRecord = {
  id: RecordId<"policy">;
  title: string;
  description?: string;
  version: number;
  status: PolicyStatus;
  selector: PolicySelector;
  rules: PolicyRule[];
  human_veto_required: boolean;
  max_ttl?: string;
  created_by: RecordId<"identity">;
  workspace: RecordId<"workspace">;
  supersedes?: RecordId<"policy">;
  created_at: string;
  updated_at?: string;
};

export type PolicyTraceEntry = {
  policy_id: string;
  policy_version: number;
  rule_id: string;
  effect: "allow" | "deny";
  matched: boolean;
  priority: number;
};

export type CreatePolicyOptions = {
  title: string;
  description?: string;
  status?: PolicyStatus;
  selector?: PolicySelector;
  rules: PolicyRule[];
  human_veto_required?: boolean;
  max_ttl?: string;
};

// ---------------------------------------------------------------------------
// Domain Helpers -- Business Language Layer
// ---------------------------------------------------------------------------

export async function createPolicy(
  surreal: Surreal,
  workspaceId: string,
  createdById: string,
  opts: CreatePolicyOptions,
