368→  // Validate text if provided: must not be empty or whitespace-only
369→  if (body.text !== undefined) {
370→    if (typeof body.text !== "string" || body.text.trim().length === 0) {
371→      return jsonError("text must not be empty", 400);
372→    }
373→  }
374→
375→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.edit.workspace_resolve.failed");
376→  if (isResponse(workspaceOrError)) return workspaceOrError;
377→  const workspaceRecord = workspaceOrError;
378→
379→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
380→  const now = new Date();
381→
382→  // Re-embed if text changed
383→  let embedding: number[] | undefined;
384→  if (body.text !== undefined) {
385→    try {
386→      embedding = await createEmbeddingVector(
387→        deps.embeddingModel,
388→        body.text.trim(),
389→        deps.config.embeddingDimension,
390→      );
391→    } catch (error) {
392→      logWarn("learning.edit.embedding_failed", "Embedding regeneration failed, updating without", {
393→        workspaceId,
394→        learningId,
395→        error: error instanceof Error ? error.message : String(error),
396→      });
397→    }
398→  }
399→
400→  try {
401→    await updateLearningFields({
402→      surreal: deps.surreal,
403→      workspaceRecord,
404→      learningRecord,
405→      fields: {
406→        ...(body.text !== undefined ? { text: body.text.trim() } : {}),
407→        ...(body.priority !== undefined ? { priority: body.priority as "low" | "medium" | "high" } : {}),
408→        ...(body.target_agents !== undefined ? { targetAgents: body.target_agents } : {}),
409→      },
410→      now,
411→      embedding,
412→    });
413→
414→    logInfo("learning.edited", "Learning edited via HTTP", {
415→      workspaceId,
416→      learningId,
417→      fieldsChanged: Object.keys(body).filter((k) => (body as Record<string, unknown>)[k] !== undefined),
418→      reEmbedded: embedding !== undefined,
419→    });
420→
421→    return jsonResponse({ status: "updated" }, 200);
422→  } catch (error) {
423→    if (error instanceof LearningNotFoundError) {
424→      return jsonError("learning not found", 404);
425→    }
426→    if (error instanceof LearningNotActiveError) {
427→      return jsonError(error.message, 409);
428→    }
429→    logError("learning.edit.failed", "Failed to edit learning", error, {
430→      workspaceId,
431→      learningId,
432→    });
433→    return jsonError("failed to edit learning", 500);
434→  }
435→}
