442→      "/api/workspaces/:workspaceId/intents/:intentId/constrain": {
443→        POST: withRequestLogging(
444→          "POST /api/workspaces/:workspaceId/intents/:intentId/constrain",
445→          "POST",
446→          (request) =>
447→            intentHandlers.handleConstrain(request.params.workspaceId, request.params.intentId, request),
448→        ),
449→      },
450→      // Intent — veto
451→      "/api/workspaces/:workspaceId/intents/:intentId/veto": {
452→        POST: withRequestLogging(
453→          "POST /api/workspaces/:workspaceId/intents/:intentId/veto",
454→          "POST",
455→          (request) =>
456→            intentHandlers.handleVeto(request.params.workspaceId, request.params.intentId, request),
457→        ),
458→      },
459→      // Intent — list pending for governance feed
460→      "/api/workspaces/:workspaceId/intents/pending": {
461→        GET: withRequestLogging(
462→          "GET /api/workspaces/:workspaceId/intents/pending",
463→          "GET",
464→          (request) => intentHandlers.handleListPending(request.params.workspaceId),
465→        ),
466→      },
467→      // Identity discovery — returns owner identity for CLI DPoP token acquisition
468→      "/api/auth/identity/:workspaceId": {
469→        GET: withRequestLogging("GET /api/auth/identity/:workspaceId", "GET", async (request) => {
470→          const wsId = request.params.workspaceId;
471→          const rows = await deps.surreal.query<[Array<{ identityId: string }>]>(
472→            `SELECT meta::id(id) AS identityId FROM identity WHERE workspace = $ws AND type = "owner" LIMIT 1;`,
473→            { ws: new RecordId("workspace", wsId) },
474→          );
475→          const row = rows[0]?.[0];
476→          if (!row) return jsonResponse({ error: "workspace_not_found" }, 404);
477→          return jsonResponse({ identity_id: row.identityId }, 200);
478→        }),
479→      },
480→      // OAuth 2.1 RAR+DPoP — Intent submission with DPoP thumbprint binding
481→      "/api/auth/intents": {
482→        POST: withRequestLogging("POST /api/auth/intents", "POST", (request) =>
483→          intentSubmissionHandler(request),
484→        ),
485→      },
486→      // OAuth 2.1 RAR+DPoP — Token endpoint
487→      "/api/auth/token": {
488→        POST: withRequestLogging("POST /api/auth/token", "POST", (request) =>
489→          tokenEndpointHandler(request),
490→        ),
491→      },
492→      // OAuth 2.1 RAR+DPoP — Bridge session-to-token exchange
493→      "/api/auth/bridge/exchange": {
494→        POST: withRequestLogging("POST /api/auth/bridge/exchange", "POST", (request) =>
495→          bridgeExchangeHandler(request),
496→        ),
497→      },
498→      // AS JWKS endpoint — public keys for token verification
499→      "/api/auth/brain/.well-known/jwks": {
500→        GET: withRequestLogging("GET /api/auth/brain/.well-known/jwks", "GET", async () =>
501→          jsonResponse(buildJwksResponse(deps.asSigningKey), 200),
502→        ),
503→      },
504→      // OAuth 2.1 discovery — proxy root-level .well-known to better-auth handler
505→      "/.well-known/oauth-authorization-server/*": {
506→        GET: async (request) => deps.auth.handler(request),
507→      },
508→      "/.well-known/oauth-protected-resource": {
509→        GET: () => jsonResponse({
510→          resource: config.betterAuthUrl,
511→          authorization_servers: [config.betterAuthUrl],
512→          scopes_supported: Object.keys(BRAIN_SCOPES),
513→          bearer_methods_supported: ["header"],
514→        }, 200),
515→      },
516→      "/api/auth/oauth-client/:clientId": {
517→        GET: withRequestLogging(
518→          "GET /api/auth/oauth-client/:clientId",
519→          "GET",
520→          createClientInfoHandler(deps.surreal),
521→        ),
522→      },
523→      "/api/auth/*": async (request) => deps.auth.handler(request),
524→      "/": appHtml,
525→      "/*": appHtml,
