530→export async function startServer(): Promise<void> {
531→  const config = loadServerConfig();
532→  const runtime = await createRuntimeDependencies(config);
533→  await ensureDefaultWorkspaceProjectScope(runtime.surreal);
534→
535→  const deps: ServerDependencies = {
536→    config,
537→    surreal: runtime.surreal,
538→    analyticsSurreal: runtime.analyticsSurreal,
539→    auth: runtime.auth,
540→    chatAgentModel: runtime.chatAgentModel,
541→    extractionModel: runtime.extractionModel,
542→    pmAgentModel: runtime.pmAgentModel,
543→    analyticsAgentModel: runtime.analyticsAgentModel,
544→    embeddingModel: runtime.embeddingModel,
545→    ...(runtime.observerModel ? { observerModel: runtime.observerModel } : {}),
546→    sse: createSseRegistry(),
547→    inflight: createInflightTracker(),
548→    asSigningKey: runtime.asSigningKey,
549→    nonceCache: createNonceCache(),
550→  };
551→
552→  const server = createBrainServer(deps);
553→
554→  // Recover intents stuck in pending_veto with expired windows (fire-and-forget)
555→  const vetoManager = createVetoManager();
556→  deps.inflight.track(
557→    vetoManager.recoverExpiredWindows({
558→      updateStatus: (intentId, status) => updateIntentStatus(deps.surreal, intentId, status),
559→      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
560→      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
561→    }).catch((err) => {
562→      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
563→    }),
564→  );
565→
566→  logInfo("server.started", "Brain app server started", {
567→    port: server.port,
568→    host: "127.0.0.1",
569→    chatAgentModelId: config.chatAgentModelId,
570→    extractionModelId: config.extractionModelId,
571→    pmAgentModelId: config.pmAgentModelId,
572→    embeddingModelId: config.embeddingModelId,
573→    embeddingDimension: config.embeddingDimension,
574→    extractionStoreThreshold: config.extractionStoreThreshold,
575→    extractionDisplayThreshold: config.extractionDisplayThreshold,
576→    surrealTransport: config.surrealUrl.startsWith("wss://")
577→      ? "wss"
578→      : config.surrealUrl.startsWith("ws://")
579→        ? "ws"
580→        : config.surrealUrl.startsWith("https://")
581→          ? "https"
582→          : "http",
583→    surrealNamespace: config.surrealNamespace,
584→    surrealDatabase: config.surrealDatabase,
585→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
586→  });
587→}
