104→export async function createPolicy(
105→  surreal: Surreal,
106→  workspaceId: string,
107→  createdById: string,
108→  opts: CreatePolicyOptions,
109→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
110→  const policyId = `policy-${crypto.randomUUID()}`;
111→  const policyRecord = new RecordId("policy", policyId);
112→  const workspaceRecord = new RecordId("workspace", workspaceId);
113→  const createdByRecord = new RecordId("identity", createdById);
114→
115→  const content: Record<string, unknown> = {
116→    title: opts.title,
117→    version: 1,
118→    status: opts.status ?? "draft",
119→    selector: opts.selector ?? {},
120→    rules: opts.rules,
121→    human_veto_required: opts.human_veto_required ?? false,
122→    created_by: createdByRecord,
123→    workspace: workspaceRecord,
124→    created_at: new Date(),
125→  };
126→
127→  if (opts.description) content.description = opts.description;
128→  if (opts.max_ttl) content.max_ttl = opts.max_ttl;
129→
130→  await surreal.query(`CREATE $policy CONTENT $content;`, {
131→    policy: policyRecord,
132→    content,
133→  });
134→
135→  return { policyId, policyRecord };
136→}
