138→export async function activatePolicy(
139→  surreal: Surreal,
140→  policyId: string,
141→  creatorId: string,
142→  workspaceId: string,
143→): Promise<void> {
144→  const policyRecord = new RecordId("policy", policyId);
145→  const creatorRecord = new RecordId("identity", creatorId);
146→  const workspaceRecord = new RecordId("workspace", workspaceId);
147→
148→  await surreal.query(`
149→    BEGIN TRANSACTION;
150→      UPDATE $policy SET status = 'active', updated_at = time::now();
151→      RELATE $creator->governing->$policy SET created_at = time::now();
152→      RELATE $policy->protects->$workspace SET created_at = time::now();
153→    COMMIT TRANSACTION;
154→  `, {
155→    policy: policyRecord,
156→    creator: creatorRecord,
157→    workspace: workspaceRecord,
158→  });
159→}
