161→export async function deprecatePolicy(
162→  surreal: Surreal,
163→  policyId: string,
164→): Promise<void> {
165→  const policyRecord = new RecordId("policy", policyId);
166→
167→  await surreal.query(`
168→    BEGIN TRANSACTION;
169→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
170→      DELETE governing WHERE out = $policy;
171→      DELETE protects WHERE in = $policy;
172→    COMMIT TRANSACTION;
173→  `, { policy: policyRecord });
174→}
