176→export async function getPolicyRecord(
177→  surreal: Surreal,
178→  policyId: string,
179→): Promise<PolicyRecord> {
180→  const policyRecord = new RecordId("policy", policyId);
181→  const rows = (await surreal.query(`SELECT * FROM $policy;`, {
182→    policy: policyRecord,
183→  })) as Array<Array<PolicyRecord>>;
184→  const result = rows[0]?.[0];
185→  if (!result) throw new Error(`Policy ${policyId} not found`);
186→  return result;
187→}
