189→export async function loadActivePoliciesForIdentity(
190→  surreal: Surreal,
191→  identityId: string,
192→  workspaceId: string,
193→): Promise<PolicyRecord[]> {
194→  const identityRecord = new RecordId("identity", identityId);
195→  const workspaceRecord = new RecordId("workspace", workspaceId);
196→
197→  // Identity-linked policies
198→  const identityPolicies = (await surreal.query(
199→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
200→    { identity: identityRecord },
201→  )) as Array<Array<{ policies: PolicyRecord[] }>>;
202→
203→  // Workspace-linked policies
204→  const workspacePolicies = (await surreal.query(
205→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
206→    { workspace: workspaceRecord },
207→  )) as Array<Array<{ policies: PolicyRecord[] }>>;
208→
209→  const idPolicies = identityPolicies[0]?.[0]?.policies ?? [];
210→  const wsPolicies = workspacePolicies[0]?.[0]?.policies ?? [];
211→
212→  // Deduplicate by policy ID and filter active only
213→  const seen = new Set<string>();
214→  const all: PolicyRecord[] = [];
215→  for (const p of [...idPolicies, ...wsPolicies]) {
216→    const id = p.id.id as string;
217→    if (!seen.has(id) && p.status === "active") {
218→      seen.add(id);
219→      all.push(p);
220→    }
221→  }
222→  return all;
223→}
