322→function base64url(buf: Buffer): string {
323→  return buf.toString("base64url");
324→}
325→
326→function generatePkce(): { verifier: string; challenge: string } {
327→  const verifier = base64url(randomBytes(32));
328→  const challenge = base64url(createHash("sha256").update(verifier).digest());
329→  return { verifier, challenge };
