522→      dpop_jwk_thumbprint: keyPair.thumbprint,
523→      action_spec: { provider: "test", action: "broad_access", params: {} },
524→      trace_id: traceRecord,
525→      requester: identityRecord,
526→      workspace: workspaceRecord,
527→      evaluation: {
528→        decision: "APPROVE",
529→        risk_score: 0,
530→        reason: "Pre-authorized for testing",
531→        evaluated_at: new Date(),
532→        policy_only: true,
533→      },
534→      created_at: new Date(),
535→    },
536→  });
537→
538→  // Request DPoP-bound access token from Custom AS
539→  const tokenUri = `${baseUrl}/api/auth/token`;
540→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
541→
542→  const tokenRes = await fetch(tokenUri, {
543→    method: "POST",
544→    headers: {
545→      "Content-Type": "application/json",
546→      DPoP: dpopProof,
547→    },
548→    body: JSON.stringify({
549→      grant_type: "urn:brain:intent-authorization",
550→      intent_id: intentId,
551→      authorization_details: broadActions,
552→    }),
553→  });
554→
555→  if (!tokenRes.ok) {
556→    const body = await tokenRes.text();
557→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
558→  }
559→
560→  const { access_token } = (await tokenRes.json()) as { access_token: string };
561→
562→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
563→    const method = options?.method ?? "POST";
564→    const requestUri = `${baseUrl}${path}`;
565→    const proof = await createDPoPProof(keyPair, method, requestUri);
566→
567→    return fetch(requestUri, {
568→      method,
569→      headers: {
570→        "Content-Type": "application/json",
571→        Authorization: `DPoP ${access_token}`,
572→        DPoP: proof,
573→      },
574→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
575→    });
576→  };
577→
578→  return {
579→    ...user,
580→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
581→    mcpFetch,
582→    accessToken: access_token,
583→    keyPair,
584→    workspaceId,
585→    identityId,
586→  };
587→}
588→
589→// ---------------------------------------------------------------------------
590→// DPoP Helpers
591→// ---------------------------------------------------------------------------
592→
593→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
594→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
595→    { name: "ECDSA", namedCurve: "P-256" },
596→    true,
597→    ["sign", "verify"],
598→  );
599→
600→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
601→  const thumbprint = await computeDPoPThumbprint(publicJwk);
602→
603→  return { privateKey, publicKey, publicJwk, thumbprint };
604→}
605→
606→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
607→  const thumbprintInput = JSON.stringify({
608→    crv: publicJwk.crv,
609→    kty: publicJwk.kty,
610→    x: publicJwk.x,
611→    y: publicJwk.y,
612→  });
613→
614→  const hashBuffer = await crypto.subtle.digest(
615→    "SHA-256",
616→    new TextEncoder().encode(thumbprintInput),
617→  );
618→
619→  return base64urlBytes(new Uint8Array(hashBuffer));
620→}
621→
622→async function createDPoPProof(
623→  keyPair: DPoPKeyPair,
624→  method: string,
625→  targetUri: string,
626→): Promise<string> {
627→  const header = {
628→    typ: "dpop+jwt" as const,
629→    alg: "ES256" as const,
630→    jwk: {
631→      kty: keyPair.publicJwk.kty,
632→      crv: keyPair.publicJwk.crv,
633→      x: keyPair.publicJwk.x,
634→      y: keyPair.publicJwk.y,
635→    },
636→  };
637→
638→  const payload = {
639→    jti: crypto.randomUUID(),
640→    htm: method,
641→    htu: targetUri,
642→    iat: Math.floor(Date.now() / 1000),
643→  };
644→
645→  const importedKey = await jose.importJWK(
646→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
647→    "ES256",
648→  );
649→
650→  return await new jose.SignJWT(payload)
651→    .setProtectedHeader(header)
652→    .sign(importedKey);
653→}
654→
655→function base64urlBytes(bytes: Uint8Array): string {
656→  const binary = String.fromCharCode(...bytes);
657→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
658→}
