672→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
673→  return await Promise.race([
674→    callback(),
675→    new Promise<T>((_, reject) => {
676→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
677→    }),
678→  ]);
679→}
